var raw = $input.first().json;
var body = raw.body || raw;
var tenantId = String(body.tenantId || '');
var fecId = String(body.fecId || '');

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('tenantId requis et doit être un UUID valide');
}
if (!fecId || !UUID_RE.test(fecId)) {
  throw new Error('fecId requis et doit être un UUID valide');
}

return [{
  json: {
    tenantId: tenantId,
    fecId: fecId
  }
}];

var fecData = $('05. Get FEC').first();

if (!fecData || !fecData.json || !fecData.json.id) {
  return [{ json: { error: 'FEC not found' } }];
}

var fec = fecData.json;
var errors = [];
var warnings = [];
var isValid = true;

var mandatoryCols = [
  'JournalCode', 'JournalLib', 'EcritureNum', 'EcritureDate',
  'CompteNum', 'CompteLib', 'CompAuxNum', 'CompAuxLib',
  'PieceRef', 'PieceDate', 'EcritureLib', 'Debit', 'Credit',
  'EcrLettrage', 'DateLettrage', 'ValidDate', 'MontantDevise', 'Idevise'
];

if (mandatoryCols.length !== 18) {
  errors.push('FEC standard requires exactly 18 columns');
  isValid = false;
}

if (fec.nombre_lignes === 0) {
  warnings.push('FEC contains no data lines (header only)');
}

if (fec.nombre_ecritures === 0) {
  errors.push('FEC contains no transactions');
  isValid = false;
}

var dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(fec.metadata?.date_generation || '')) {
  warnings.push('Date generation format may not be standard');
}

return [{
  json: {
    fec: fec,
    errors: errors,
    warnings: warnings,
    isValid: isValid
  }
}];

var updateData = $('07. Update Status').first();
var validationData = $('06. Validate Structure').first().json;

if (!updateData || !updateData.json) {
  return [{ json: { success: false, error: 'Update failed' } }];
}

return [{
  json: {
    success: true,
    isValid: validationData.isValid,
    errors: validationData.errors,
    warnings: validationData.warnings,
    statut: updateData.json.statut,
    dateValidation: updateData.json.date_validation
  }
}];
